Create reusable infrastructure for testing functions that use exec.Command.

## Target Functions
- `runApprovedRequest` (run.go:243)
- `runSafeCommand` (run.go:181) - after Phase 2 extraction

## Deliverable: internal/testutil/executor.go

```go
package testutil

import (
    "os/exec"
)

// CommandExecutor abstracts command execution for testing
type CommandExecutor interface {
    Run(name string, args ...string) ([]byte, error)
    Start(name string, args ...string) (*exec.Cmd, error)
}

// RealExecutor uses actual exec.Command (production)
type RealExecutor struct{}

func (r RealExecutor) Run(name string, args ...string) ([]byte, error) {
    return exec.Command(name, args...).CombinedOutput()
}

func (r RealExecutor) Start(name string, args ...string) (*exec.Cmd, error) {
    cmd := exec.Command(name, args...)
    return cmd, cmd.Start()
}

// MockExecutor records and simulates command execution (testing)
type MockExecutor struct {
    RecordedCalls []CommandCall
    MockOutput    []byte
    MockError     error
    MockExitCode  int
}

type CommandCall struct {
    Name string
    Args []string
}

func (m *MockExecutor) Run(name string, args ...string) ([]byte, error) {
    m.RecordedCalls = append(m.RecordedCalls, CommandCall{Name: name, Args: args})
    return m.MockOutput, m.MockError
}

// NewMockExecutor creates a mock with configurable behavior
func NewMockExecutor(output []byte, err error) *MockExecutor {
    return &MockExecutor{MockOutput: output, MockError: err}
}
```

## Refactoring Required
Functions using exec.Command need a small refactor:

```go
// Before
func runApprovedRequest(req *Request) error {
    cmd := exec.Command(req.Command.Raw, req.Command.Args...)
    return cmd.Run()
}

// After
var executor CommandExecutor = RealExecutor{}

func runApprovedRequest(req *Request) error {
    _, err := executor.Run(req.Command.Raw, req.Command.Args...)
    return err
}
```

